import React, { useState, useEffect } from 'react';
import axios from 'axios';

const FILE_ID = 'NBHU5lsSfPTBMnlFVPxHNB';
const FIGMA_TOKEN = 'figd_9IgwTEDRk2P6kWhTjRvtOmkFcAKniW9pPya9ohwA';
const BUTTON_NODE_ID = '1334&node-type=symbol&t=elWvEGKoCs0T5xvf-0';

/**
 * Format the button data to keep only relevant properties
 * @param {Object} data - Raw data from Figma API
 * @returns {Object} - Simplified button data
 */
const formatButtonData = (data) => ({
    name: data.name,
    type: data.type,
    color: data.fills?.[0]?.color,
    width: data.absoluteBoundingBox?.width,
    height: data.absoluteBoundingBox?.height,
});

const FigmaButton = () => {
    const [buttonData, setButtonData] = useState(null);

    useEffect(() => {
        const fetchButtonData = async () => {
            try {
                const response = await axios.get(
                    `https://api.figma.com/v1/files/${FILE_ID}/nodes?ids=${BUTTON_NODE_ID}`,
                    {
                        headers: { 'X-Figma-Token': FIGMA_TOKEN },
                    }
                );

                // Retrieve and format button data
                const rawData = response.data.nodes[BUTTON_NODE_ID].document;
                const formattedData = formatButtonData(rawData); // Format raw data
                setButtonData(formattedData); // Set the simplified data to state
            } catch (error) {
                console.error('Error fetching button data:', error);
            }
        };

        fetchButtonData();
    }, []);

    return (
        <div>
            {buttonData ? (
                <div>
                    <h3>{buttonData.name}</h3>
                    <p>Type: {buttonData.type}</p>
                    <p>Color: {JSON.stringify(buttonData.color)}</p>
                    <p>Width: {buttonData.width}px, Height: {buttonData.height}px</p>
                </div>
            ) : (
                <p>Loading button data...</p>
            )}
        </div>
    );
};

export default FigmaButton;
